from itertools import combinations
adj = [[False] * n for _ in range(n)]
for i, j in E:
    adj[i][j] = adj[j][i] = True
def is_clique(S):
    return all(adj[i][j] for i in S for j in S if i != j)
def clique_number(S):
    for size in range(len(S), 0, -1):
        for C in combinations(S, size):
            if is_clique(C):
                return size
    return 0
def chromatic_number(S):
    k = 0
    while True:
        color = {}
        def backtrack(idx):
            if idx == len(S):
                return True
            v = S[idx]
            for c in range(k):
                if all(color.get(u) != c for u in S[:idx] if adj[v][u]):
                    color[v] = c
                    if backtrack(idx + 1):
                        return True
                    del color[v]
            return False
        if backtrack(0):
            return k
        k += 1
for size in range(n + 1):
    for S in combinations(range(n), size):
        assert chromatic_number(list(S)) == clique_number(list(S))

